    #[test]
    fn insert_middle() {
        let vector = [1, 2, 3].as_vector();
        let result = vector.insert(1, 99);
        assert_eq(result.len(), 4);
        assert_eq(result, [1, 99, 2, 3].as_vector());
    }

    #[test]
    fn insert_end() {
        let vector = [1, 2, 3].as_vector();
        let result = vector.insert(3, 4);
        assert_eq(result.len(), 4);
        assert_eq(result, [1, 2, 3, 4].as_vector());
